import{_ as e,c as a,o as t,a as s}from"./app.b38afc27.js";const g=JSON.parse('{"title":"Domain Model","description":"","frontmatter":{},"headers":[{"level":2,"title":"Overview","slug":"overview","link":"#overview","children":[]},{"level":2,"title":"Aggregates","slug":"aggregates","link":"#aggregates","children":[{"level":3,"title":"Reservation","slug":"reservation","link":"#reservation","children":[]},{"level":3,"title":"Payment","slug":"payment","link":"#payment","children":[]}]},{"level":2,"title":"Entities","slug":"entities","link":"#entities","children":[{"level":3,"title":"Hall","slug":"hall","link":"#hall","children":[]},{"level":3,"title":"Seat","slug":"seat","link":"#seat","children":[]},{"level":3,"title":"Screening","slug":"screening","link":"#screening","children":[]},{"level":3,"title":"ScreeningSeat","slug":"screeningseat","link":"#screeningseat","children":[]}]},{"level":2,"title":"Value Objects","slug":"value-objects","link":"#value-objects","children":[{"level":3,"title":"Money","slug":"money","link":"#money","children":[]}]},{"level":2,"title":"Domain Events","slug":"domain-events","link":"#domain-events","children":[]},{"level":2,"title":"Invariants Summary","slug":"invariants-summary","link":"#invariants-summary","children":[]}],"relativePath":"domain-model.md"}'),n={name:"domain-model.md"},o=s(`<h1 id="domain-model" tabindex="-1">Domain Model <a class="header-anchor" href="#domain-model" aria-hidden="true">#</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-hidden="true">#</a></h2><p>The domain is organized around five core concepts: halls, seats, screenings, reservations, and payments. Two of these \u2014 <code>Reservation</code> and <code>Payment</code> \u2014 are aggregates that own domain logic and raise domain events. The rest are entities or value objects that support them.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">Hall</span></span>
<span class="line"><span style="color:#A6ACCD;"> \u2514\u2500\u2500 Seat[]</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">Screening</span></span>
<span class="line"><span style="color:#A6ACCD;"> \u2514\u2500\u2500 ScreeningSeat[]  (projection of Seat into a specific screening)</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">Reservation  \u2190 AggregateRoot</span></span>
<span class="line"><span style="color:#A6ACCD;">Payment      \u2190 AggregateRoot</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><hr><h2 id="aggregates" tabindex="-1">Aggregates <a class="header-anchor" href="#aggregates" aria-hidden="true">#</a></h2><h3 id="reservation" tabindex="-1">Reservation <a class="header-anchor" href="#reservation" aria-hidden="true">#</a></h3><p>Represents a user&#39;s intent to purchase seats for a screening. Created with a 5-minute expiry window.</p><p><strong>State transitions:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">Pending \u2192 Confirmed</span></span>
<span class="line"><span style="color:#A6ACCD;">Pending \u2192 Cancelled</span></span>
<span class="line"><span style="color:#A6ACCD;">Pending \u2192 Expired</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p>A confirmed reservation cannot be cancelled or expired.</p><p><strong>Domain events raised:</strong></p><table><thead><tr><th>Event</th><th>When</th></tr></thead><tbody><tr><td><code>ReservationCreated</code></td><td>On construction</td></tr><tr><td><code>ReservationConfirmed</code></td><td>On <code>Confirm()</code></td></tr></tbody></table><p><strong>Key properties:</strong></p><table><thead><tr><th>Property</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>Id</code></td><td><code>Guid</code></td><td></td></tr><tr><td><code>EventId</code></td><td><code>Guid</code></td><td></td></tr><tr><td><code>ScreeningId</code></td><td><code>Guid</code></td><td></td></tr><tr><td><code>SeatIds</code></td><td><code>List&lt;Guid&gt;</code></td><td>Physical seat references</td></tr><tr><td><code>Status</code></td><td><code>ReservationStatus</code></td><td></td></tr><tr><td><code>CreatedAt</code></td><td><code>DateTime</code></td><td></td></tr><tr><td><code>ExpiredAt</code></td><td><code>DateTime?</code></td><td>Set to <code>CreatedAt + 5 minutes</code></td></tr></tbody></table><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki"><code><span class="line"><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">enum</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">ReservationStatus</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">Pending</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">Confirmed</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">Cancelled</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">Expired</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><hr><h3 id="payment" tabindex="-1">Payment <a class="header-anchor" href="#payment" aria-hidden="true">#</a></h3><p>Represents the financial transaction tied to a reservation.</p><p><strong>State transitions:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">Pending \u2192 Completed</span></span>
<span class="line"><span style="color:#A6ACCD;">Pending \u2192 Failed</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p>A payment that is already completed or failed cannot transition again.</p><p><strong>Domain events raised:</strong></p><table><thead><tr><th>Event</th><th>When</th></tr></thead><tbody><tr><td><code>PaymentCompleted</code></td><td>On <code>Complete()</code></td></tr></tbody></table><p><strong>Key properties:</strong></p><table><thead><tr><th>Property</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>Id</code></td><td><code>Guid</code></td><td></td></tr><tr><td><code>ReservationId</code></td><td><code>Guid</code></td><td></td></tr><tr><td><code>Amount</code></td><td><code>Money</code></td><td>Value object</td></tr><tr><td><code>Status</code></td><td><code>PaymentStatus</code></td><td></td></tr><tr><td><code>CreatedAt</code></td><td><code>DateTime</code></td><td></td></tr></tbody></table><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki"><code><span class="line"><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">enum</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">PaymentStatus</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">Pending</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">Completed</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">Failed</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><hr><h2 id="entities" tabindex="-1">Entities <a class="header-anchor" href="#entities" aria-hidden="true">#</a></h2><h3 id="hall" tabindex="-1">Hall <a class="header-anchor" href="#hall" aria-hidden="true">#</a></h3><p>Represents a physical venue. Owns a collection of <code>Seat</code> entities.</p><p><strong>Invariants enforced:</strong></p><ul><li>Name cannot be empty</li><li>Must have at least one seat</li><li>No two seats can share the same row and column</li><li>A seat can only be added if its <code>HallId</code> matches the hall</li></ul><hr><h3 id="seat" tabindex="-1">Seat <a class="header-anchor" href="#seat" aria-hidden="true">#</a></h3><p>Represents a physical seat in a hall. Immutable after creation.</p><table><thead><tr><th>Property</th><th>Type</th></tr></thead><tbody><tr><td><code>Id</code></td><td><code>Guid</code></td></tr><tr><td><code>HallId</code></td><td><code>Guid</code></td></tr><tr><td><code>Row</code></td><td><code>string</code></td></tr><tr><td><code>Column</code></td><td><code>int</code></td></tr></tbody></table><p>Row cannot be empty, column must be greater than 0.</p><hr><h3 id="screening" tabindex="-1">Screening <a class="header-anchor" href="#screening" aria-hidden="true">#</a></h3><p>Represents a specific showing of an event in a hall at a given time. Owns a collection of <code>ScreeningSeat</code> entities.</p><p><strong>Useful queries exposed:</strong></p><ul><li><code>GetAvailableSeats()</code> \u2014 seats with status <code>Available</code></li><li><code>GetAvailableSeatCount()</code> / <code>GetTotalSeatCount()</code></li><li><code>GetOccupancyRatio()</code> \u2014 fraction of seats that are reserved or sold</li></ul><hr><h3 id="screeningseat" tabindex="-1">ScreeningSeat <a class="header-anchor" href="#screeningseat" aria-hidden="true">#</a></h3><p>A projection of a physical <code>Seat</code> into a specific <code>Screening</code>. Tracks booking status and is the primary concurrency target.</p><p><strong>State transitions:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">Available \u2192 Reserved \u2192 Sold</span></span>
<span class="line"><span style="color:#A6ACCD;">Reserved  \u2192 Available  (via Release)</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p>A sold seat cannot be released.</p><p><strong>Concurrency token:</strong></p><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki"><code><span class="line"><span style="color:#89DDFF;">[</span><span style="color:#FFCB6B;">Timestamp</span><span style="color:#89DDFF;">]</span></span>
<span class="line"><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> uint Version </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> get</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">private</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">set</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>EF Core uses <code>Version</code> to detect concurrent updates. See <a href="./concurrency.html">concurrency.md</a> for details.</p><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki"><code><span class="line"><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">enum</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">ScreeningSeatStatus</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">Available</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">Reserved</span><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">1</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">Sold</span><span style="color:#A6ACCD;">      </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">2</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><hr><h2 id="value-objects" tabindex="-1">Value Objects <a class="header-anchor" href="#value-objects" aria-hidden="true">#</a></h2><h3 id="money" tabindex="-1">Money <a class="header-anchor" href="#money" aria-hidden="true">#</a></h3><p>Wraps <code>Amount</code> (decimal) and <code>Currency</code> (string). Used on <code>Payment</code> to avoid primitive obsession on financial values.</p><hr><h2 id="domain-events" tabindex="-1">Domain Events <a class="header-anchor" href="#domain-events" aria-hidden="true">#</a></h2><p>Events are raised inside aggregates via <code>AddDomainEvent()</code> and persisted to the outbox in the same transaction as the state change. See <a href="./outbox-pattern.html">outbox-pattern.md</a> for how they are dispatched.</p><table><thead><tr><th>Event</th><th>Raised by</th><th>Triggers</th></tr></thead><tbody><tr><td><code>ReservationCreated</code></td><td><code>Reservation</code> constructor</td><td>Payment creation</td></tr><tr><td><code>ReservationConfirmed</code></td><td><code>Reservation.Confirm()</code></td><td>Seat marking as sold</td></tr><tr><td><code>PaymentCompleted</code></td><td><code>Payment.Complete()</code></td><td>Reservation confirmation</td></tr></tbody></table><hr><h2 id="invariants-summary" tabindex="-1">Invariants Summary <a class="header-anchor" href="#invariants-summary" aria-hidden="true">#</a></h2><table><thead><tr><th>Rule</th><th>Enforced in</th></tr></thead><tbody><tr><td>Seat can only be reserved if <code>Available</code></td><td><code>ScreeningSeat.Reserve()</code></td></tr><tr><td>Seat can only be sold if <code>Reserved</code></td><td><code>ScreeningSeat.MarkAsSold()</code></td></tr><tr><td>Sold seat cannot be released</td><td><code>ScreeningSeat.Release()</code></td></tr><tr><td>Reservation can only be confirmed if <code>Pending</code></td><td><code>Reservation.Confirm()</code></td></tr><tr><td>Confirmed reservation cannot be cancelled or expired</td><td><code>Reservation.Cancel/Expire()</code></td></tr><tr><td>Payment can only complete or fail if <code>Pending</code></td><td><code>Payment.Complete/Fail()</code></td></tr><tr><td>Hall seat positions must be unique</td><td><code>Hall.AddSeat()</code></td></tr></tbody></table>`,64),l=[o];function d(r,c,i,p,h,y){return t(),a("div",null,l)}const u=e(n,[["render",d]]);export{g as __pageData,u as default};
